157→async function getLatestVersionCached(): Promise<string | null> {
158→  try {
159→    if (!browser.runtime?.id) return null;
160→
161→    const now = Date.now();
162→    const cache = await browser.storage.local.get(LATEST_VERSION_CACHE_KEY);
163→    const cached = cache?.[LATEST_VERSION_CACHE_KEY] as
164→      | { version?: string; fetchedAt?: number }
165→      | undefined;
166→    if (
167→      cached &&
168→      cached.version &&
169→      cached.fetchedAt &&
170→      now - cached.fetchedAt < LATEST_VERSION_MAX_AGE
171→    ) {
172→      return cached.version;
173→    }
174→
175→    const resp = await fetch(
176→      'https://api.github.com/repos/Nagi-ovo/gemini-voyager/releases/latest',
177→      {
178→        headers: { Accept: 'application/vnd.github+json' },
179→      },
180→    );
181→    if (!resp.ok) {
182→      throw new Error(`HTTP ${resp.status}`);
183→    }
184→
185→    const data = await resp.json();
186→    const candidate =
187→      typeof data.tag_name === 'string'
188→        ? data.tag_name
189→        : typeof data.name === 'string'
190→          ? data.name
191→          : null;
192→
193→    if (candidate) {
194→      await browser.storage.local.set({
195→        [LATEST_VERSION_CACHE_KEY]: { version: candidate, fetchedAt: now },
196→      });
197→      return candidate;
198→    }
199→  } catch (error) {
200→    pmLogger.debug('Latest version check failed', { error });
201→  }
202→  return null;
203→}
