 1→/**
 2→ * RTL (Right-to-Left) detection utilities.
 3→ * Used to adapt the extension's UI for RTL languages like Arabic.
 4→ */
 5→
 6→/** Language codes that use RTL text direction */
 7→const RTL_LANGUAGES = new Set(['ar', 'he', 'fa', 'ur']);
 8→
 9→function getUrlLanguageHint(): string | null {
10→  try {
11→    const params = new URLSearchParams(window.location.search);
12→    const candidates = [params.get('hl'), params.get('lang'), params.get('locale')];
13→    for (const candidate of candidates) {
14→      if (candidate && candidate.trim()) return candidate.trim();
15→    }
16→  } catch {
17→    // Ignore URL parsing failures and continue with other signals.
18→  }
19→  return null;
20→}
21→
22→/**
23→ * Returns true if the given BCP 47 language code is an RTL language.
24→ */
25→export function isRTLLanguage(lang: string): boolean {
26→  return RTL_LANGUAGES.has(lang.split('-')[0].toLowerCase());
27→}
28→
29→/**
30→ * Detects if the current UI context is RTL.
31→ *
32→ * Checks in priority order:
33→ * 1. The `dir` attribute on the `<html>` element (set by the host page)
34→ * 2. The `lang` attribute on the `<html>` element
35→ * 3. The provided extension UI language setting
36→ */
37→export function detectRTL(extensionLanguage?: string | null): boolean {
38→  // 1. Page-level dir attribute is the most authoritative signal
39→  const pageDir = document.documentElement.dir || document.body.dir;
40→  if (pageDir === 'rtl') return true;
41→  if (pageDir === 'ltr') return false;
42→
43→  // 2. Page language attribute
44→  const pageLang = document.documentElement.lang?.split('-')[0]?.toLowerCase();
45→  if (pageLang && RTL_LANGUAGES.has(pageLang)) return true;
46→
47→  // 3. Host URL hint (e.g. Gemini `?hl=ar`)
48→  const urlLangHint = getUrlLanguageHint();
49→  if (urlLangHint) return isRTLLanguage(urlLangHint);
50→
51→  // 4. Extension UI language stored in settings
52→  if (extensionLanguage && isRTLLanguage(extensionLanguage)) return true;
53→
54→  return false;
55→}
56→
57→/** CSS class added to `document.body` to activate RTL layout overrides */
58→export const GV_RTL_CLASS = 'gv-rtl';
59→
60→/**
61→ * Applies or removes the RTL body class based on the detected direction.
62→ * @returns true if RTL was applied, false otherwise
63→ */
64→export function applyRTLClass(extensionLanguage?: string | null): boolean {
65→  const rtl = detectRTL(extensionLanguage);
66→  document.body.classList.toggle(GV_RTL_CLASS, rtl);
67→  return rtl;
68→}
