  flex-direction: column;
  width: 440px;
  max-width: calc(100vw - 20px);
  max-height: min(75vh, 600px);
  overflow: hidden;
  --gv-pm-surface: oklch(0.995 0.002 250);
  border-radius: 18px;
  background: oklch(0.995 0.002 250);
  border: 1px solid oklch(0.92 0.004 250 / 0.7);
  box-shadow:
    0 16px 48px oklch(0 0 0 / 0.12),
    0 6px 20px oklch(0 0 0 / 0.06);
  z-index: 999;
  color: oklch(0.14 0.004 285);
  font-family:
    ui-sans-serif,
    system-ui,
    -apple-system,
    Segoe UI,
    Roboto,
    Helvetica,
    Arial,
    'Apple Color Emoji',
    'Segoe UI Emoji';
}

@media (prefers-color-scheme: dark) {
  .gv-pm-panel {
    --gv-pm-surface: oklch(0.2 0.008 285);
