    color: oklch(0.92 0.004 250);
    border-color: oklch(0.3 0.008 285 / 0.7);
    box-shadow:
      0 16px 48px oklch(0 0 0 / 0.4),
      0 6px 20px oklch(0 0 0 / 0.25);
  }
}

.theme-host.dark-theme .gv-pm-panel,
body.dark-theme .gv-pm-panel {
  --gv-pm-surface: oklch(0.2 0.008 285);
