  right: 6px;
}

.gv-aistudio .gv-folder-pin-btn {
  right: 28px;
}

.gv-aistudio .gv-folder-header-actions .gv-folder-action-btn {
  padding: 2px;
}

/* Ensure pin/more icons are perfectly centered and not clipped */
.gv-aistudio .gv-folder-pin-btn .google-symbols,
.gv-aistudio .gv-folder-actions-btn .google-symbols {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 24px;
  /* match button box */
  height: 24px;
  line-height: 24px;
  overflow: visible !important;
  /* never clip emoji */
}

.gv-aistudio .gv-folder-pin-btn .google-symbols::before,
.gv-aistudio .gv-folder-actions-btn .google-symbols::before {
  width: 24px;
  height: 24px;
  line-height: 24px;
  text-align: center;
  font-size: 20px;
  /* slightly larger for better visual balance */
}

/* Icon fallbacks: hide ligature text and use simple glyphs */
.gv-aistudio .gv-folder-pin-btn .google-symbols,
.gv-aistudio .gv-folder-add-btn .google-symbols,
.gv-aistudio .gv-folder-actions-btn .google-symbols,
.gv-aistudio .gv-folder-expand-btn .google-symbols,
.gv-aistudio .gv-folder-icon.google-symbols,
.gv-aistudio .gv-conversation-icon.google-symbols,
.gv-aistudio .gv-folder-action-btn .google-symbols,
