 4→
 5→import baseConfig, { baseBuildOptions, baseManifest } from './vite.config.base';
 6→
 7→const outDir = resolve(__dirname, 'dist_firefox');
 8→const FIREFOX_CHANGELOG_BANNER_RESOURCES = [
 9→  'changelog-promo-banner.png',
10→  'changelog-promo-banner-cn.png',
11→  'changelog-promo-banner-jp.png',
12→];
13→
14→type WebAccessibleResourceLike = {
15→  resources?: string[];
16→};
17→
18→type FirefoxManifestLike<TResource extends WebAccessibleResourceLike = WebAccessibleResourceLike> =
19→  {
20→    web_accessible_resources?: TResource[];
21→  };
22→
23→function appendFirefoxChangelogResources<
24→  TManifest extends FirefoxManifestLike<TResource>,
25→  TResource extends WebAccessibleResourceLike,
26→>(manifest: TManifest): TManifest {
27→  const existingEntries = manifest.web_accessible_resources ?? [];
28→  if (existingEntries.length === 0) return manifest;
29→
30→  const [first, ...rest] = existingEntries;
31→  const existingResources = first.resources ?? [];
32→  const mergedResources = Array.from(
33→    new Set([...existingResources, ...FIREFOX_CHANGELOG_BANNER_RESOURCES]),
34→  );
35→
36→  return {
37→    ...manifest,
38→    web_accessible_resources: [
39→      {
40→        ...first,
41→        resources: mergedResources,
42→      },
43→      ...rest,
44→    ],
45→  } as TManifest;
46→}
47→
48→export default mergeConfig(
49→  baseConfig,
50→  defineConfig({
51→    plugins: [
52→      crx({
53→        manifest: appendFirefoxChangelogResources({
54→          ...baseManifest,
55→          browser_specific_settings: {
56→            gecko: {
57→              id: 'gemini-voyager@nagi-ovo',
58→              strict_min_version: '115.0',
59→              data_collection_permissions: {
60→                required: ['none'],
61→              },
62→            },
63→          },
64→          background: {
65→            scripts: ['src/pages/background/index.ts'],
66→            type: 'module',
67→          },
68→        } as unknown as FirefoxManifestLike) as unknown as ManifestV3Export,
69→        browser: 'firefox',
70→        contentScripts: {
71→          injectCss: true,
72→        },
73→      }),
74→    ],
75→    resolve: {
76→      alias: {
77→        // Firefox uses mermaid v9.2.2 (max compatible version)
78→        // Chrome/Safari use mermaid v11.x (latest) by default
79→        mermaid: 'mermaid-legacy',
80→      },
81→    },
82→    build: {
83→      ...baseBuildOptions,
84→      outDir,
85→    },
86→    publicDir: resolve(__dirname, 'public'),
87→  }),
