  1→import fs from 'fs';
  2→import { resolve } from 'path';
  3→import type { NormalizedInputOptions, NormalizedOutputOptions } from 'rollup';
  4→import type { PluginOption } from 'vite';
  5→
  6→const FIREFOX_OUT_DIR_MARKER = 'dist_firefox';
  7→const CHANGELOG_PROMO_BANNERS = [
  8→  'changelog-promo-banner.png',
  9→  'changelog-promo-banner-cn.png',
 10→  'changelog-promo-banner-jp.png',
 11→];
 12→
 13→// plugin to remove dev icons from prod build
 14→export function stripDevIcons(isDev: boolean) {
 15→  if (isDev) return null;
 16→
 17→  return {
 18→    name: 'strip-dev-icons',
 19→    resolveId(source: string) {
 20→      return source === 'virtual-module' ? source : null;
 21→    },
 22→    renderStart(outputOptions: NormalizedOutputOptions, _inputOptions: NormalizedInputOptions) {
 23→      const outDir = outputOptions.dir ?? '';
 24→      const isFirefoxBuild = outDir.includes(FIREFOX_OUT_DIR_MARKER);
 25→
 26→      fs.rm(resolve(outDir, 'dev-icon-32.png'), () =>
 27→        console.log(`Deleted dev-icon-32.png from prod build`),
 28→      );
 29→      fs.rm(resolve(outDir, 'dev-icon-128.png'), () =>
 30→        console.log(`Deleted dev-icon-128.png from prod build`),
 31→      );
 32→
 33→      if (!isFirefoxBuild) {
 34→        CHANGELOG_PROMO_BANNERS.forEach((fileName) => {
 35→          fs.rm(resolve(outDir, fileName), () =>
 36→            console.log(`Deleted ${fileName} from non-Firefox build`),
 37→          );
 38→        });
 39→      }
 40→
 41→      // Remove assets directory if it exists
 42→      const assetsDir = resolve(outDir, 'assets');
 43→      fs.rm(assetsDir, { recursive: true, force: true }, () =>
 44→        console.log(`Deleted assets/ directory from prod build`),
 45→      );
 46→    },
 47→    writeBundle(outputOptions: NormalizedOutputOptions) {
 48→      const outDir = outputOptions.dir ?? '';
 49→      // Remove .vite directory (Vite's internal manifest, not needed for extension)
 50→      const viteDir = resolve(outDir, '.vite');
 51→      fs.rm(viteDir, { recursive: true, force: true }, () =>
 52→        console.log(`Deleted .vite/ directory from prod build`),
 53→      );
 54→    },
 55→  };
 56→}
