 58→type LocaleMessages = Record<string, { message: string; description?: string }>;
 59→
 60→function stripDescriptions(raw: LocaleMessages): LocaleMessages {
 61→  return Object.fromEntries(Object.entries(raw).map(([k, v]) => [k, { message: v.message }]));
 62→}
 63→
 64→// plugin to strip `description` fields from locale JSON at build time.
 65→// Runs before vite:json so we return stripped JSON; vite:json then converts it to ESM normally.
 66→export function stripI18nDescriptions(isDev: boolean): PluginOption {
 67→  if (isDev) return null;
 68→
 69→  return {
 70→    name: 'strip-i18n-descriptions',
 71→    enforce: 'pre',
 72→    transform(code, id) {
 73→      if (!id.includes('/locales/') || !id.endsWith('messages.json')) return null;
 74→      const raw: LocaleMessages = JSON.parse(code);
 75→      return { code: JSON.stringify(stripDescriptions(raw)), map: null };
 76→    },
 77→  };
 78→}
 79→
 80→// plugin to support i18n
 81→export function crxI18n(options: {
 82→  localize: boolean;
 83→  src: string;
 84→  stripDescriptions?: boolean;
 85→}): PluginOption {
 86→  if (!options.localize) return null;
 87→
 88→  const getJsonFiles = (dir: string): Array<string> => {
 89→    const files = fs.readdirSync(dir, { recursive: true }) as string[];
 90→    return files.filter((file) => !!file && file.endsWith('.json'));
 91→  };
 92→  const entry = resolve(__dirname, options.src);
 93→  const localeFiles = getJsonFiles(entry);
 94→  const files = localeFiles.map((file) => {
 95→    const raw: LocaleMessages = JSON.parse(fs.readFileSync(resolve(entry, file), 'utf-8'));
 96→    const source = options.stripDescriptions
 97→      ? JSON.stringify(stripDescriptions(raw))
