  1→/**
  2→ * Browser detection utilities
  3→ * Provides reliable browser detection for Safari-specific handling
  4→ */
  5→
  6→/**
  7→ * Detect if the current browser is Safari
  8→ *
  9→ * Detection strategy:
 10→ * 1. Check for Safari-specific vendor string (Apple Inc.)
 11→ * 2. Ensure 'safari' is in user agent
 12→ * 3. Ensure it's not Chrome/Chromium (which also uses webkit)
 13→ *
 14→ * Note: Do not rely on global objects (browser/chrome) for detection,
 15→ * as webextension-polyfill makes browser available in all browsers,
 16→ * and Firefox provides both browser and chrome objects.
 17→ *
 18→ * @returns true if running in Safari
 19→ */
 20→export function isSafari(): boolean {
 21→  // Reliable detection using user agent and vendor
 22→  const ua = navigator.userAgent.toLowerCase();
 23→  const vendor = navigator.vendor.toLowerCase();
 24→
 25→  // Safari has 'Apple' vendor and 'safari' in UA, but not 'chrome'
 26→  const isAppleVendor = vendor.includes('apple');
 27→  const hasSafariUA = ua.includes('safari');
 28→  const notChrome = !ua.includes('chrome') && !ua.includes('chromium');
 29→
 30→  return isAppleVendor && hasSafariUA && notChrome;
 31→}
 32→
 33→/**
 34→ * Check if update reminders should be shown on Safari
 35→ * This is controlled by the ENABLE_SAFARI_UPDATE_CHECK environment variable at build time
 36→ *
 37→ * @returns true if Safari update reminders are enabled
 38→ */
 39→export function shouldShowSafariUpdateReminder(): boolean {
 40→  if (!isSafari()) return false;
 41→
 42→  // Check build-time flag (injected via vite config)
 43→  // Default: false (disabled)
 44→  try {
 45→    return import.meta.env.ENABLE_SAFARI_UPDATE_CHECK === 'true';
 46→  } catch {
 47→    return false;
 48→  }
 49→}
 50→
 51→/**
 52→ * Detect if the current browser is Chrome (not Edge, Firefox, or Safari).
 53→ * Used to conditionally show Chrome Web Store rating prompts.
 54→ */
 55→export function isChrome(): boolean {
 56→  if (isSafari()) return false;
 57→  const ua = navigator.userAgent.toLowerCase();
 58→  return (
 59→    (ua.includes('chrome') || ua.includes('chromium')) &&
 60→    !ua.includes('edg') &&
 61→    !ua.includes('firefox')
 62→  );
 63→}
 64→
 65→/**
 66→ * Detect if the current browser is Firefox.
 67→ */
 68→export function isFirefox(): boolean {
 69→  const ua = navigator.userAgent.toLowerCase();
 70→  return ua.includes('firefox');
 71→}
 72→
 73→/**
 74→ * Detect if the current platform is macOS
 75→ *
 76→ * @returns true if running on macOS
 77→ */
 78→export function isMac(): boolean {
 79→  // navigator.platform is deprecated but still widely supported and reliable
 80→  // Use it first, then fall back to userAgent
 81→  if (typeof navigator !== 'undefined') {
 82→    if (navigator.platform) {
 83→      return navigator.platform.toUpperCase().includes('MAC');
 84→    }
 85→    return /macintosh|mac os x/i.test(navigator.userAgent);
 86→  }
 87→  return false;
 88→}
 89→
 90→/**
 91→ * Get the platform-appropriate modifier key label
 92→ * macOS: ⌘ (Cmd), others: Ctrl
 93→ *
 94→ * @returns '⌘' on macOS, 'Ctrl' on other platforms
 95→ */
 96→export function getModifierKey(): string {
 97→  return isMac() ? '⌘' : 'Ctrl';
 98→}
 99→
100→/**
101→ * Get browser name for debugging
102→ * Uses user agent detection for reliability
103→ */
104→export function getBrowserName(): string {
105→  if (isSafari()) return 'Safari';
106→
107→  if (isFirefox()) return 'Firefox';
108→
109→  const ua = navigator.userAgent.toLowerCase();
110→
111→  // Chrome/Edge/Brave have 'chrome' or 'chromium' in UA
112→  if (ua.includes('chrome') || ua.includes('chromium')) {
113→    if (ua.includes('edg')) return 'Edge';
114→    return 'Chrome/Chromium';
115→  }
116→
117→  return 'Unknown';
118→}
