  1→/**
  2→ * Safari-specific storage adapter
  3→ * Uses browser.storage.local for reliable persistence on Safari
  4→ *
  5→ * Why Safari needs this:
  6→ * - Safari's localStorage has 7-day deletion policy
  7→ * - Random data loss on iOS 13+
  8→ * - Private mode quota exceeded errors
  9→ *
 10→ * Solution:
 11→ * - Use browser.storage.local (persistent, 10MB quota)
 12→ * - Fallback to localStorage if storage API unavailable
 13→ */
 14→import browser from 'webextension-polyfill';
 15→
 16→interface SafariStorageAdapter {
 17→  getItem(key: string): Promise<string | null>;
 18→  setItem(key: string, value: string): Promise<void>;
 19→  removeItem(key: string): Promise<void>;
 20→}
 21→
 22→/**
 23→ * Safari storage adapter using browser.storage.local
 24→ * Provides async methods that replace localStorage for Safari
 25→ */
 26→export class SafariStorage implements SafariStorageAdapter {
 27→  /**
 28→   * Get item from browser.storage.local
 29→   */
 30→  async getItem(key: string): Promise<string | null> {
 31→    try {
 32→      const result = await browser.storage.local.get(key);
 33→      const value = result[key];
 34→      // Ensure we return string or null
 35→      if (typeof value === 'string') {
 36→        return value;
 37→      }
 38→      return null;
 39→    } catch (error) {
 40→      console.error('[SafariStorage] Failed to get item:', key, error);
 41→      // Fallback to localStorage
 42→      try {
 43→        return localStorage.getItem(key);
 44→      } catch {
 45→        return null;
 46→      }
 47→    }
 48→  }
 49→
 50→  /**
 51→   * Set item to browser.storage.local
 52→   */
 53→  async setItem(key: string, value: string): Promise<void> {
 54→    try {
 55→      await browser.storage.local.set({ [key]: value });
 56→    } catch (error) {
 57→      console.error('[SafariStorage] Failed to set item:', key, error);
 58→      // Fallback to localStorage
 59→      try {
 60→        localStorage.setItem(key, value);
 61→      } catch (fallbackError) {
 62→        console.error('[SafariStorage] Fallback to localStorage also failed:', fallbackError);
 63→        throw error;
 64→      }
 65→    }
 66→  }
 67→
 68→  /**
 69→   * Remove item from browser.storage.local
 70→   */
 71→  async removeItem(key: string): Promise<void> {
 72→    try {
 73→      await browser.storage.local.remove(key);
 74→    } catch (error) {
 75→      console.error('[SafariStorage] Failed to remove item:', key, error);
 76→      // Fallback to localStorage
 77→      try {
 78→        localStorage.removeItem(key);
 79→      } catch {
 80→        // Ignore fallback errors for remove
 81→      }
 82→    }
 83→  }
 84→
 85→  /**
 86→   * Migrate data from localStorage to browser.storage.local
 87→   * Should be called once during initialization
 88→   */
 89→  async migrateFromLocalStorage(key: string): Promise<boolean> {
 90→    try {
 91→      // Check if already migrated
 92→      const migrationKey = `${key}_migrated`;
 93→      const alreadyMigrated = await this.getItem(migrationKey);
 94→      if (alreadyMigrated === 'true') {
 95→        return true;
 96→      }
 97→
 98→      // Check if there's data in localStorage
 99→      const localData = localStorage.getItem(key);
100→      if (!localData) {
101→        // No data to migrate, mark as migrated
102→        await this.setItem(migrationKey, 'true');
103→        return true;
104→      }
105→
106→      // Check if browser.storage.local already has data
107→      const browserData = await browser.storage.local.get(key);
108→      if (browserData[key]) {
109→        // Data already in browser.storage.local, no migration needed
110→        await this.setItem(migrationKey, 'true');
111→        return true;
112→      }
113→
114→      // Migrate data
115→      await this.setItem(key, localData);
116→      await this.setItem(migrationKey, 'true');
117→
118→      console.log(
119→        `[SafariStorage] Successfully migrated ${key} from localStorage to browser.storage.local`,
120→      );
121→      return true;
122→    } catch (error) {
123→      console.error('[SafariStorage] Migration failed:', error);
124→      return false;
125→    }
126→  }
127→}
128→
129→/**
130→ * Singleton instance
131→ */
132→export const safariStorage = new SafariStorage();
133→

