  1→/**
  2→ * Rain Effect for Gemini — inspired by "The Garden of Words"
  3→ *
  4→ * A cinematic rain with depth layers, wind-angled streaks, and
  5→ * tiny splash ripples where drops hit the viewport floor.
  6→ *
  7→ * Graceful transitions: when switching effects or disabling, existing
  8→ * raindrops continue falling naturally with final splash ripples.
  9→ * New drops stop spawning, and the canvas is cleaned up once all
 10→ * particles and splashes have left the viewport.
 11→ *
 12→ * Visual approach:
 13→ * - Raindrops are thin, semi-transparent lines (not dots), drawn
 14→ *   at a slight wind angle (~8°) for realism.
 15→ * - Three depth layers: far mist, mid rain, near foreground.
 16→ *   Each layer has its own speed, length, opacity, and thickness.
 17→ * - When a drop reaches the bottom, it spawns a short-lived splash
 18→ *   ring that expands and fades out.
 19→ * - Colour: cool blue-grey (hsl 210–220) to evoke the melancholy
 20→ *   atmosphere of Shinjuku Gyoen in the rain.
 21→ */
 22→
 23→const CANVAS_ID = 'gv-rain-effect-canvas';
 24→const STORAGE_KEY = 'gvVisualEffect';
 25→const LEGACY_KEY = 'gvSnowEffect';
 26→const EFFECT_VALUE = 'rain';
 27→
 28→/** Wind angle in radians (~8° from vertical) */
 29→const WIND_ANGLE = 0.14;
 30→const WIND_DX = Math.sin(WIND_ANGLE);
 31→const WIND_DY = Math.cos(WIND_ANGLE);
 32→
 33→const LAYERS = [
 34→  // far — misty fine drizzle
 35→  {
 36→    count: 80,
 37→    length: [6, 14],
 38→    speed: [3, 6],
 39→    opacity: [0.06, 0.14],
 40→    width: [0.3, 0.6],
 41→  },
 42→  // mid — main rain
 43→  {
 44→    count: 60,
 45→    length: [14, 28],
 46→    speed: [7, 13],
 47→    opacity: [0.12, 0.25],
 48→    width: [0.5, 1.0],
 49→  },
 50→  // near — heavy foreground streaks
 51→  {
 52→    count: 30,
 53→    length: [26, 48],
 54→    speed: [12, 20],
 55→    opacity: [0.2, 0.38],
 56→    width: [0.8, 1.5],
 57→  },
 58→] as const;
 59→
 60→/** Maximum concurrent splashes */
 61→const MAX_SPLASHES = 24;
 62→
 63→interface Raindrop {
 64→  x: number;
 65→  y: number;
 66→  length: number;
 67→  speed: number;
 68→  opacity: number;
 69→  lineWidth: number;
 70→  /** Whether this drop can spawn a splash (only near/mid layers) */
 71→  canSplash: boolean;
 72→}
 73→
 74→interface Splash {
 75→  x: number;
 76→  y: number;
 77→  radius: number;
 78→  maxRadius: number;
 79→  opacity: number;
 80→  fadeSpeed: number;
 81→  expandSpeed: number;
 82→}
 83→
 84→/** Effect lifecycle: off → active ⇄ draining → off */
 85→let state: 'off' | 'active' | 'draining' = 'off';
 86→let canvas: HTMLCanvasElement | null = null;
 87→let ctx: CanvasRenderingContext2D | null = null;
 88→let animationFrameId: number | null = null;
 89→let drops: Raindrop[] = [];
 90→let splashes: Splash[] = [];
 91→let resizeHandler: (() => void) | null = null;
 92→let visibilityHandler: (() => void) | null = null;
 93→
 94→function rand(min: number, max: number): number {
 95→  return min + Math.random() * (max - min);
 96→}
 97→
 98→function createDrop(
 99→  canvasWidth: number,
100→  canvasHeight: number,
101→  layer: (typeof LAYERS)[number],
102→  randomY: boolean,
103→  canSplash: boolean,
104→): Raindrop {
105→  return {
106→    x: Math.random() * (canvasWidth + 100) - 50,
107→    y: randomY ? Math.random() * canvasHeight : -(Math.random() * canvasHeight * 0.3),
108→    length: rand(layer.length[0], layer.length[1]),
109→    speed: rand(layer.speed[0], layer.speed[1]),
110→    opacity: rand(layer.opacity[0], layer.opacity[1]),
111→    lineWidth: rand(layer.width[0], layer.width[1]),
112→    canSplash,
113→  };
114→}
115→
116→function initDrops(width: number, height: number): void {
117→  const items: Raindrop[] = [];
118→  for (let li = 0; li < LAYERS.length; li++) {
119→    const layer = LAYERS[li];
120→    const canSplash = li >= 1; // mid + near
121→    for (let i = 0; i < layer.count; i++) {
122→      items.push(createDrop(width, height, layer, true, canSplash));
123→    }
124→  }
125→  drops = items;
126→  splashes = [];
127→}
128→
129→function spawnSplash(x: number, y: number): void {
130→  if (splashes.length >= MAX_SPLASHES) return;
131→  splashes.push({
132→    x,
133→    y,
134→    radius: 0.5,
135→    maxRadius: rand(3, 8),
136→    opacity: rand(0.15, 0.3),
137→    fadeSpeed: rand(0.004, 0.01),
138→    expandSpeed: rand(0.15, 0.4),
139→  });
140→}
141→
142→function updateAndDraw(_time: number): void {
143→  if (!ctx || !canvas) return;
144→
145→  const { width, height } = canvas;
146→  ctx.clearRect(0, 0, width, height);
147→
148→  // --- Draw rain streaks ---
149→  ctx.lineCap = 'round';
150→
151→  let currentOpacity = -1;
152→  let currentWidth = -1;
153→  let visibleDropCount = 0;
154→
155→  for (const d of drops) {
156→    const prevY = d.y;
157→
158→    // Move
159→    d.x += d.speed * WIND_DX;
160→    d.y += d.speed * WIND_DY;
161→
162→    // Off-screen bottom
163→    if (d.y > height + d.length) {
164→      if (state === 'draining') {
165→        // Spawn one final splash as the drop exits (only on first crossing)
166→        if (prevY <= height + d.length && d.canSplash && Math.random() < 0.35) {
167→          spawnSplash(d.x, height - 1);
168→        }
169→        continue;
170→      }
171→      // Normal: recycle + splash
172→      if (d.canSplash && Math.random() < 0.35) {
173→        spawnSplash(d.x, height - 1);
174→      }
175→      d.y = -(d.length + Math.random() * height * 0.2);
176→      d.x = Math.random() * (width + 100) - 50;
177→    }
178→
179→    // Off-screen right (wind pushes drops rightward)
180→    if (d.x > width + 50) {
181→      if (state === 'draining') {
182→        continue;
183→      }
184→      d.x = -50;
185→    }
186→
187→    visibleDropCount++;
188→
189→    // Batch strokeStyle
190→    const qo = Math.round(d.opacity * 30) / 30;
191→    if (qo !== currentOpacity) {
192→      currentOpacity = qo;
193→      ctx.strokeStyle = `rgba(180,200,220,${currentOpacity})`;
194→    }
195→    const qw = Math.round(d.lineWidth * 4) / 4;
196→    if (qw !== currentWidth) {
197→      currentWidth = qw;
198→      ctx.lineWidth = currentWidth;
199→    }
200→
201→    ctx.beginPath();
202→    ctx.moveTo(d.x, d.y);
203→    ctx.lineTo(d.x + d.length * WIND_DX, d.y + d.length * WIND_DY);
204→    ctx.stroke();
205→  }
206→
207→  // --- Draw splashes ---
208→  ctx.lineWidth = 0.6;
209→  for (let i = splashes.length - 1; i >= 0; i--) {
210→    const s = splashes[i];
211→    s.radius += s.expandSpeed;
212→    s.opacity -= s.fadeSpeed;
213→
214→    if (s.opacity <= 0 || s.radius >= s.maxRadius) {
215→      splashes.splice(i, 1);
216→      continue;
217→    }
218→
219→    ctx.strokeStyle = `rgba(180,200,220,${s.opacity})`;
220→    ctx.beginPath();
221→    ctx.ellipse(s.x, s.y, s.radius, s.radius * 0.35, 0, 0, Math.PI * 2);
222→    ctx.stroke();
223→  }
224→
225→  // All drops off-screen and all splashes faded — finish draining
226→  if (state === 'draining' && visibleDropCount === 0 && splashes.length === 0) {
227→    finalizeDrain();
228→    return;
229→  }
230→
231→  animationFrameId = requestAnimationFrame(updateAndDraw);
232→}
233→
234→function resizeCanvas(): void {
235→  if (!canvas) return;
236→  canvas.width = window.innerWidth;
237→  canvas.height = window.innerHeight;
238→}
239→
240→function startAnimation(): void {
241→  if (animationFrameId !== null) return;
242→  animationFrameId = requestAnimationFrame(updateAndDraw);
243→}
244→
245→function stopAnimation(): void {
246→  if (animationFrameId !== null) {
247→    cancelAnimationFrame(animationFrameId);
248→    animationFrameId = null;
249→  }
250→}
251→
252→function handleVisibilityChange(): void {
253→  if (document.visibilityState === 'visible') {
254→    startAnimation();
255→  } else {
256→    stopAnimation();
257→  }
258→}
259→
260→function enable(): void {
261→  if (state === 'active') return;
262→  if (state === 'draining') {
263→    // Cancel drain — resume normal drop recycling
264→    state = 'active';
265→    return;
266→  }
267→  state = 'active';
268→
269→  canvas = document.createElement('canvas');
270→  canvas.id = CANVAS_ID;
271→  canvas.style.cssText =
272→    'position:fixed;top:0;left:0;width:100%;height:100%;pointer-events:none;z-index:2147483647;';
273→  document.documentElement.appendChild(canvas);
274→
275→  ctx = canvas.getContext('2d');
276→  if (!ctx) {
277→    forceDisable();
278→    return;
279→  }
280→
281→  resizeCanvas();
282→  initDrops(canvas.width, canvas.height);
283→  startAnimation();
284→
285→  resizeHandler = resizeCanvas;
286→  window.addEventListener('resize', resizeHandler);
287→
288→  visibilityHandler = handleVisibilityChange;
289→  document.addEventListener('visibilitychange', visibilityHandler);
290→}
291→
292→/**
293→ * Graceful disable: stop spawning new drops and let existing ones
294→ * fall off with final splash ripples.
295→ */
296→function disable(): void {
297→  if (state !== 'active') return;
298→  state = 'draining';
299→}
300→
301→/** Complete the drain: remove canvas and clean up all resources. */
302→function finalizeDrain(): void {
303→  state = 'off';
304→  stopAnimation();
305→
306→  if (resizeHandler) {
307→    window.removeEventListener('resize', resizeHandler);
308→    resizeHandler = null;
309→  }
310→
311→  if (visibilityHandler) {
312→    document.removeEventListener('visibilitychange', visibilityHandler);
313→    visibilityHandler = null;
314→  }
315→
316→  if (canvas) {
317→    canvas.remove();
318→    canvas = null;
319→  }
320→
321→  ctx = null;
322→  drops = [];
323→  splashes = [];
324→}
325→
326→/** Immediate disable: remove everything without draining (e.g. page unload). */
327→function forceDisable(): void {
328→  if (state === 'off') return;
329→  finalizeDrain();
330→}
331→
332→function resolveEffect(res: Record<string, unknown>): string {
333→  if (typeof res[STORAGE_KEY] === 'string') return res[STORAGE_KEY] as string;
334→  if (res[LEGACY_KEY] === true) return 'snow';
335→  return 'off';
336→}
337→
338→export function startRainEffect(): void {
339→  try {
340→    chrome.storage?.sync?.get({ [STORAGE_KEY]: null, [LEGACY_KEY]: false }, (res) => {
341→      if (resolveEffect(res) === EFFECT_VALUE) {
342→        enable();
343→      }
344→    });
345→  } catch (e) {
346→    console.error('[Gemini Voyager] Failed to get rain effect setting:', e);
347→  }
348→
349→  try {
350→    chrome.storage?.onChanged?.addListener((changes, area) => {
351→      if (area === 'sync' && changes[STORAGE_KEY]) {
352→        if (changes[STORAGE_KEY].newValue === EFFECT_VALUE) {
353→          enable();
354→        } else {
355→          disable();
356→        }
357→      }
358→    });
359→  } catch (e) {
360→    console.error('[Gemini Voyager] Failed to add storage listener for rain effect:', e);
361→  }
362→
363→  window.addEventListener('beforeunload', () => {
364→    forceDisable();
365→  });
366→}
367→

  1→/**
  2→ * Sakura (Cherry Blossom) Effect for Gemini
  3→ *
  4→ * Renders a fullscreen canvas with gently falling sakura petals.
  5→ * Uses `pointer-events: none` so it never blocks page interactions.
  6→ * Pauses when the tab is hidden to save CPU.
  7→ *
  8→ * Graceful transitions: when switching effects or disabling, existing
  9→ * petals continue falling naturally instead of vanishing instantly.
 10→ * New petals stop spawning, and the canvas is cleaned up once all
 11→ * particles have left the viewport.
 12→ *
 13→ * Visual approach:
 14→ * - Petal shape: wide, rounded heart-like silhouette with a small
 15→ *   V-notch — drawn via quadratic bezier curves. Width ≈ height
 16→ *   so it reads as a petal, not a leaf.
 17→ * - 3D flutter: gentle oscillating scaleX (never fully flips) to
 18→ *   simulate a petal wobbling in the air, not aggressively tumbling.
 19→ * - Colour: very pale pink, almost white — the hallmark of somei
 20→ *   yoshino cherry blossoms.
 21→ * - Motion: slow fall, wide lazy drift + tiny fast flutter. Petals
 22→ *   feel like they're floating, not dropping.
 23→ */
 24→
 25→const CANVAS_ID = 'gv-sakura-effect-canvas';
 26→const STORAGE_KEY = 'gvVisualEffect';
 27→const LEGACY_KEY = 'gvSnowEffect';
 28→const EFFECT_VALUE = 'sakura';
 29→
 30→const LAYERS = [
 31→  // far — tiny, slow, ghostly
 32→  { count: 40, size: [2.5, 4.5], speed: [0.1, 0.3], opacity: [0.1, 0.25], drift: [0.15, 0.4] },
 33→  // mid — main visible petals
 34→  { count: 32, size: [4.5, 7.5], speed: [0.25, 0.55], opacity: [0.25, 0.5], drift: [0.35, 0.8] },
 35→  // near — large, soft foreground
 36→  { count: 16, size: [7.5, 11], speed: [0.4, 0.75], opacity: [0.4, 0.65], drift: [0.5, 1.0] },
 37→] as const;
 38→
 39→/**
 40→ * Somei-yoshino palette: extremely pale pinks, almost white.
 41→ * Pre-built fill prefixes — append opacity + `)`.
 42→ */
 43→const PALETTE = [
 44→  'hsla(350,50%,94%,', // near-white blush
 45→  'hsla(348,55%,92%,', // faint pink
 46→  'hsla(345,60%,90%,', // soft petal
 47→  'hsla(340,50%,92%,', // warm white-pink
 48→  'hsla(346,65%,88%,', // gentle sakura
 49→  'hsla(342,45%,93%,', // whisper pink
 50→  'hsla(352,40%,95%,', // almost white
 51→  'hsla(338,55%,89%,', // subtle rose
 52→] as const;
 53→
 54→interface Petal {
 55→  x: number;
 56→  y: number;
 57→  /** Overall size scale of this petal */
 58→  size: number;
 59→  opacity: number;
 60→  speedY: number;
 61→
 62→  // primary sway — slow, wide
 63→  drift: number;
 64→  driftFreq: number;
 65→  phase: number;
 66→
 67→  // secondary flutter — fast, tiny
 68→  flutter: number;
 69→  flutterFreq: number;
 70→
 71→  // 2D spin
 72→  rotation: number;
 73→  rotationSpeed: number;
 74→
 75→  // 3D wobble — gentle scaleX oscillation (never fully flips)
 76→  wobblePhase: number;
 77→  wobbleSpeed: number;
 78→  /** Baseline scaleX (0.6–1.0); wobble oscillates around this */
 79→  wobbleBase: number;
 80→  /** Amplitude of scaleX wobble (0.15–0.35) */
 81→  wobbleAmp: number;
 82→
 83→  colorIdx: number;
 84→}
 85→
 86→/** Effect lifecycle: off → active ⇄ draining → off */
 87→let state: 'off' | 'active' | 'draining' = 'off';
 88→let canvas: HTMLCanvasElement | null = null;
 89→let ctx: CanvasRenderingContext2D | null = null;
 90→let animationFrameId: number | null = null;
 91→let petals: Petal[] = [];
 92→let resizeHandler: (() => void) | null = null;
 93→let visibilityHandler: (() => void) | null = null;
 94→
 95→function rand(min: number, max: number): number {
 96→  return min + Math.random() * (max - min);
 97→}
 98→
 99→function createPetal(
100→  canvasWidth: number,
101→  canvasHeight: number,
102→  layer: (typeof LAYERS)[number],
103→  randomY: boolean,
104→): Petal {
105→  return {
106→    x: Math.random() * canvasWidth,
107→    y: randomY ? Math.random() * canvasHeight : -(Math.random() * canvasHeight * 0.4),
108→    size: rand(layer.size[0], layer.size[1]),
109→    opacity: rand(layer.opacity[0], layer.opacity[1]),
110→    speedY: rand(layer.speed[0], layer.speed[1]),
111→
112→    drift: rand(layer.drift[0], layer.drift[1]),
113→    driftFreq: rand(0.0003, 0.0009),
114→    phase: Math.random() * Math.PI * 2,
115→
116→    flutter: rand(0.04, 0.15),
117→    flutterFreq: rand(0.002, 0.006),
118→
119→    rotation: Math.random() * Math.PI * 2,
120→    rotationSpeed: rand(0.001, 0.008) * (Math.random() > 0.5 ? 1 : -1),
121→
122→    wobblePhase: Math.random() * Math.PI * 2,
123→    wobbleSpeed: rand(0.0006, 0.002),
124→    wobbleBase: rand(0.6, 0.9),
125→    wobbleAmp: rand(0.15, 0.35),
126→
127→    colorIdx: Math.floor(Math.random() * PALETTE.length),
128→  };
129→}
130→
131→function initPetals(width: number, height: number): void {
132→  const items: Petal[] = [];
133→  for (const layer of LAYERS) {
134→    for (let i = 0; i < layer.count; i++) {
135→      items.push(createPetal(width, height, layer, true));
136→    }
137→  }
138→  items.sort((a, b) => a.colorIdx - b.colorIdx || a.opacity - b.opacity);
139→  petals = items;
140→}
141→
142→/**
143→ * Draw a sakura petal centred at the origin.
144→ *
145→ * Shape: wide, rounded, heart-like with a small notch at the top.
146→ * Width ≈ 85% of height — reads as a petal, not a leaf.
147→ *
148→ *        ╱ ‿ ╲        ← notch
149→ *      ╱       ╲
150→ *     (         )      ← round, fat body
151→ *      ╲       ╱
152→ *        ╲   ╱
153→ *          V           ← stem point
154→ */
155→function tracePetal(c: CanvasRenderingContext2D, s: number): void {
156→  // s = half-height; width is deliberately close to height
157→  const w = s * 0.85;
158→
159→  c.beginPath();
160→
161→  // Bottom stem point
162→  c.moveTo(0, s);
163→
164→  // Right side — sweeps up and out in a fat curve
165→  c.quadraticCurveTo(w * 1.1, s * 0.15, w * 0.2, -s * 0.85);
166→
167→  // Top-right → notch centre
168→  c.quadraticCurveTo(w * 0.05, -s * 0.55, 0, -s * 0.65);
169→
170→  // Notch centre → top-left
171→  c.quadraticCurveTo(-w * 0.05, -s * 0.55, -w * 0.2, -s * 0.85);
172→
173→  // Left side — mirror sweep back to stem
174→  c.quadraticCurveTo(-w * 1.1, s * 0.15, 0, s);
175→
176→  c.closePath();
177→}
178→
179→function updateAndDraw(time: number): void {
180→  if (!ctx || !canvas) return;
181→
182→  const { width, height } = canvas;
183→  ctx.clearRect(0, 0, width, height);
184→
185→  let currentFill = '';
186→  let visibleCount = 0;
187→
188→  for (const p of petals) {
189→    // Gentle fall + dual-frequency sway
190→    p.y += p.speedY;
191→    p.x +=
192→      Math.sin(p.phase + time * p.driftFreq) * p.drift +
193→      Math.sin(p.phase * 2.7 + time * p.flutterFreq) * p.flutter;
194→    p.rotation += p.rotationSpeed;
195→
196→    // Recycle off-screen (or skip during drain)
197→    if (p.y > height + p.size * 2) {
198→      if (state === 'draining') {
199→        continue;
200→      }
201→      p.y = -p.size * 2;
202→      p.x = Math.random() * width;
203→    }
204→
205→    visibleCount++;
206→
207→    if (p.x > width + p.size * 2) {
208→      p.x = -p.size * 2;
209→    } else if (p.x < -p.size * 2) {
210→      p.x = width + p.size * 2;
211→    }
212→
213→    // Fill batching
214→    const qOpacity = Math.round(p.opacity * 20) / 20;
215→    const nextFill = PALETTE[p.colorIdx] + qOpacity + ')';
216→    if (nextFill !== currentFill) {
217→      currentFill = nextFill;
218→      ctx.fillStyle = currentFill;
219→    }
220→
221→    // 3D wobble — gentle scaleX oscillation, always positive (no full flip)
222→    const wobble = p.wobbleBase + Math.sin(p.wobblePhase + time * p.wobbleSpeed) * p.wobbleAmp;
223→
224→    ctx.save();
225→    ctx.translate(p.x, p.y);
226→    ctx.rotate(p.rotation);
227→    ctx.scale(wobble, 1);
228→
229→    tracePetal(ctx, p.size);
230→    ctx.fill();
231→
232→    ctx.restore();
233→  }
234→
235→  // All petals have left the viewport — finish draining
236→  if (state === 'draining' && visibleCount === 0) {
237→    finalizeDrain();
238→    return;
239→  }
240→
241→  animationFrameId = requestAnimationFrame(updateAndDraw);
242→}
243→
244→function resizeCanvas(): void {
245→  if (!canvas) return;
246→  canvas.width = window.innerWidth;
247→  canvas.height = window.innerHeight;
248→}
249→
250→function startAnimation(): void {
251→  if (animationFrameId !== null) return;
252→  animationFrameId = requestAnimationFrame(updateAndDraw);
253→}
254→
255→function stopAnimation(): void {
256→  if (animationFrameId !== null) {
257→    cancelAnimationFrame(animationFrameId);
258→    animationFrameId = null;
259→  }
260→}
261→
262→function handleVisibilityChange(): void {
263→  if (document.visibilityState === 'visible') {
264→    startAnimation();
265→  } else {
266→    stopAnimation();
267→  }
268→}
269→
270→function enable(): void {
271→  if (state === 'active') return;
272→  if (state === 'draining') {
273→    // Cancel drain — resume normal particle recycling
274→    state = 'active';
275→    return;
276→  }
277→  state = 'active';
278→
279→  canvas = document.createElement('canvas');
280→  canvas.id = CANVAS_ID;
281→  canvas.style.cssText =
282→    'position:fixed;top:0;left:0;width:100%;height:100%;pointer-events:none;z-index:2147483647;';
283→  document.documentElement.appendChild(canvas);
284→
285→  ctx = canvas.getContext('2d');
286→  if (!ctx) {
287→    forceDisable();
288→    return;
289→  }
290→
291→  resizeCanvas();
292→  initPetals(canvas.width, canvas.height);
293→  startAnimation();
294→
295→  resizeHandler = resizeCanvas;
296→  window.addEventListener('resize', resizeHandler);
297→
298→  visibilityHandler = handleVisibilityChange;
299→  document.addEventListener('visibilitychange', visibilityHandler);
300→}
301→
302→/**
303→ * Graceful disable: stop spawning new petals and let existing ones
304→ * fall off the bottom of the viewport naturally.
305→ */
306→function disable(): void {
307→  if (state !== 'active') return;
308→  state = 'draining';
309→}
310→
311→/** Complete the drain: remove canvas and clean up all resources. */
312→function finalizeDrain(): void {
313→  state = 'off';
314→  stopAnimation();
315→
316→  if (resizeHandler) {
317→    window.removeEventListener('resize', resizeHandler);
318→    resizeHandler = null;
319→  }
320→
321→  if (visibilityHandler) {
322→    document.removeEventListener('visibilitychange', visibilityHandler);
323→    visibilityHandler = null;
324→  }
325→
326→  if (canvas) {
327→    canvas.remove();
328→    canvas = null;
329→  }
330→
331→  ctx = null;
332→  petals = [];
333→}
334→
335→/** Immediate disable: remove everything without draining (e.g. page unload). */
336→function forceDisable(): void {
337→  if (state === 'off') return;
338→  finalizeDrain();
339→}
340→
341→function resolveEffect(res: Record<string, unknown>): string {
342→  if (typeof res[STORAGE_KEY] === 'string') return res[STORAGE_KEY] as string;
343→  if (res[LEGACY_KEY] === true) return 'snow';
344→  return 'off';
345→}
346→
347→export function startSakuraEffect(): void {
348→  try {
349→    chrome.storage?.sync?.get({ [STORAGE_KEY]: null, [LEGACY_KEY]: false }, (res) => {
350→      if (resolveEffect(res) === EFFECT_VALUE) {
351→        enable();
352→      }
353→    });
354→  } catch (e) {
355→    console.error('[Gemini Voyager] Failed to get sakura effect setting:', e);
356→  }
357→
358→  try {
359→    chrome.storage?.onChanged?.addListener((changes, area) => {
360→      if (area === 'sync' && changes[STORAGE_KEY]) {
361→        if (changes[STORAGE_KEY].newValue === EFFECT_VALUE) {
362→          enable();
363→        } else {
364→          disable();
365→        }
366→      }
367→    });
368→  } catch (e) {
369→    console.error('[Gemini Voyager] Failed to add storage listener for sakura effect:', e);
370→  }
371→
372→  window.addEventListener('beforeunload', () => {
373→    forceDisable();
374→  });
375→}
