 87→/**
 88→ * Check if current hostname matches any custom websites
 89→ */
 90→async function isCustomWebsite(): Promise<boolean> {
 91→  try {
 92→    const result = await chrome.storage?.sync?.get({ gvPromptCustomWebsites: [] });
 93→    const customWebsites = Array.isArray(result?.gvPromptCustomWebsites)
 94→      ? result.gvPromptCustomWebsites
 95→      : [];
 96→
 97→    // Normalize current hostname
 98→    const currentHost = location.hostname.toLowerCase().replace(/^www\./, '');
 99→
100→    console.log('[Gemini Voyager] Checking custom websites:', {
101→      currentHost,
102→      customWebsites,
103→      hostname: location.hostname,
104→    });
105→
106→    const isCustom = customWebsites.some((website: string) => {
107→      const normalizedWebsite = website.toLowerCase().replace(/^www\./, '');
108→      const matches =
109→        currentHost === normalizedWebsite || currentHost.endsWith('.' + normalizedWebsite);
110→      console.log('[Gemini Voyager] Comparing:', { currentHost, normalizedWebsite, matches });
111→      return matches;
112→    });
113→
114→    console.log('[Gemini Voyager] Is custom website:', isCustom);
115→    return isCustom;
116→  } catch (e) {
117→    if (isExtensionContextInvalidatedError(e)) {
118→      return false;
119→    }
120→    console.error('[Gemini Voyager] Error checking custom websites:', e);
121→    return false;
122→  }
123→}
