319→/**
320→ * Determine initialization delay based on tab visibility
321→ */
322→function getInitializationDelay(): number {
323→  // Check if tab is currently visible
324→  const isVisible = document.visibilityState === 'visible';
325→
326→  if (isVisible) {
327→    // Foreground tab: initialize immediately for good UX
328→    console.log('[Gemini Voyager] Foreground tab detected, initializing immediately');
329→    return 0;
330→  } else {
331→    // Background tab: add random delay to distribute load across multiple tabs
332→    const randomRange = BACKGROUND_TAB_MAX_DELAY - BACKGROUND_TAB_MIN_DELAY;
333→    const randomDelay = BACKGROUND_TAB_MIN_DELAY + Math.random() * randomRange;
334→    console.log(
335→      `[Gemini Voyager] Background tab detected, delaying initialization by ${Math.round(randomDelay)}ms`,
336→    );
337→    return randomDelay;
338→  }
339→}
