341→/**
342→ * Handle tab visibility changes
343→ */
344→function handleVisibilityChange(): void {
345→  if (document.visibilityState === 'visible' && !initialized) {
346→    // Tab became visible before initialization completed
347→    // Cancel any pending delayed initialization and start immediately
348→    if (initializationTimer !== null) {
349→      clearTimeout(initializationTimer);
350→      initializationTimer = null;
351→      console.log('[Gemini Voyager] Tab became visible, initializing immediately');
352→    }
353→    initializeFeatures();
354→  }
