  1→/**
  2→ * Sakura (Cherry Blossom) Effect for Gemini
  3→ *
  4→ * Renders a fullscreen canvas with gently falling sakura petals.
  5→ * Uses `pointer-events: none` so it never blocks page interactions.
  6→ * Pauses when the tab is hidden to save CPU.
  7→ *
  8→ * Graceful transitions: when switching effects or disabling, existing
  9→ * petals continue falling naturally instead of vanishing instantly.
 10→ * New petals stop spawning, and the canvas is cleaned up once all
 11→ * particles have left the viewport.
 12→ *
 13→ * Visual approach:
 14→ * - Petal shape: wide, rounded heart-like silhouette with a small
 15→ *   V-notch — drawn via quadratic bezier curves. Width ≈ height
 16→ *   so it reads as a petal, not a leaf.
 17→ * - 3D flutter: gentle oscillating scaleX (never fully flips) to
 18→ *   simulate a petal wobbling in the air, not aggressively tumbling.
 19→ * - Colour: very pale pink, almost white — the hallmark of somei
 20→ *   yoshino cherry blossoms.
 21→ * - Motion: slow fall, wide lazy drift + tiny fast flutter. Petals
 22→ *   feel like they're floating, not dropping.
 23→ */
 24→
 25→const CANVAS_ID = 'gv-sakura-effect-canvas';
 26→const STORAGE_KEY = 'gvVisualEffect';
 27→const LEGACY_KEY = 'gvSnowEffect';
 28→const EFFECT_VALUE = 'sakura';
 29→
 30→const LAYERS = [
 31→  // far — tiny, slow, ghostly
 32→  { count: 40, size: [2.5, 4.5], speed: [0.1, 0.3], opacity: [0.1, 0.25], drift: [0.15, 0.4] },
 33→  // mid — main visible petals
 34→  { count: 32, size: [4.5, 7.5], speed: [0.25, 0.55], opacity: [0.25, 0.5], drift: [0.35, 0.8] },
 35→  // near — large, soft foreground
 36→  { count: 16, size: [7.5, 11], speed: [0.4, 0.75], opacity: [0.4, 0.65], drift: [0.5, 1.0] },
 37→] as const;
 38→
 39→/**
 40→ * Somei-yoshino palette: extremely pale pinks, almost white.
 41→ * Pre-built fill prefixes — append opacity + `)`.
 42→ */
 43→const PALETTE = [
 44→  'hsla(350,50%,94%,', // near-white blush
 45→  'hsla(348,55%,92%,', // faint pink
 46→  'hsla(345,60%,90%,', // soft petal
 47→  'hsla(340,50%,92%,', // warm white-pink
 48→  'hsla(346,65%,88%,', // gentle sakura
 49→  'hsla(342,45%,93%,', // whisper pink
 50→  'hsla(352,40%,95%,', // almost white
 51→  'hsla(338,55%,89%,', // subtle rose
 52→] as const;
 53→
 54→interface Petal {
 55→  x: number;
 56→  y: number;
 57→  /** Overall size scale of this petal */
 58→  size: number;
 59→  opacity: number;
 60→  speedY: number;
 61→
 62→  // primary sway — slow, wide
 63→  drift: number;
 64→  driftFreq: number;
 65→  phase: number;
 66→
 67→  // secondary flutter — fast, tiny
 68→  flutter: number;
 69→  flutterFreq: number;
 70→
 71→  // 2D spin
 72→  rotation: number;
 73→  rotationSpeed: number;
 74→
 75→  // 3D wobble — gentle scaleX oscillation (never fully flips)
 76→  wobblePhase: number;
 77→  wobbleSpeed: number;
 78→  /** Baseline scaleX (0.6–1.0); wobble oscillates around this */
 79→  wobbleBase: number;
 80→  /** Amplitude of scaleX wobble (0.15–0.35) */
 81→  wobbleAmp: number;
 82→
 83→  colorIdx: number;
 84→}
 85→
 86→/** Effect lifecycle: off → active ⇄ draining → off */
 87→let state: 'off' | 'active' | 'draining' = 'off';
 88→let canvas: HTMLCanvasElement | null = null;
 89→let ctx: CanvasRenderingContext2D | null = null;
 90→let animationFrameId: number | null = null;
 91→let petals: Petal[] = [];
 92→let resizeHandler: (() => void) | null = null;
 93→let visibilityHandler: (() => void) | null = null;
 94→
 95→function rand(min: number, max: number): number {
 96→  return min + Math.random() * (max - min);
 97→}
 98→
 99→function createPetal(
100→  canvasWidth: number,
101→  canvasHeight: number,
102→  layer: (typeof LAYERS)[number],
103→  randomY: boolean,
104→): Petal {
105→  return {
106→    x: Math.random() * canvasWidth,
107→    y: randomY ? Math.random() * canvasHeight : -(Math.random() * canvasHeight * 0.4),
108→    size: rand(layer.size[0], layer.size[1]),
109→    opacity: rand(layer.opacity[0], layer.opacity[1]),
110→    speedY: rand(layer.speed[0], layer.speed[1]),
111→
112→    drift: rand(layer.drift[0], layer.drift[1]),
113→    driftFreq: rand(0.0003, 0.0009),
114→    phase: Math.random() * Math.PI * 2,
115→
116→    flutter: rand(0.04, 0.15),
117→    flutterFreq: rand(0.002, 0.006),
118→
119→    rotation: Math.random() * Math.PI * 2,
120→    rotationSpeed: rand(0.001, 0.008) * (Math.random() > 0.5 ? 1 : -1),
121→
122→    wobblePhase: Math.random() * Math.PI * 2,
123→    wobbleSpeed: rand(0.0006, 0.002),
124→    wobbleBase: rand(0.6, 0.9),
125→    wobbleAmp: rand(0.15, 0.35),
126→
127→    colorIdx: Math.floor(Math.random() * PALETTE.length),
128→  };
129→}
130→
131→function initPetals(width: number, height: number): void {
132→  const items: Petal[] = [];
133→  for (const layer of LAYERS) {
134→    for (let i = 0; i < layer.count; i++) {
135→      items.push(createPetal(width, height, layer, true));
136→    }
137→  }
138→  items.sort((a, b) => a.colorIdx - b.colorIdx || a.opacity - b.opacity);
139→  petals = items;
140→}
141→
142→/**
143→ * Draw a sakura petal centred at the origin.
144→ *
145→ * Shape: wide, rounded, heart-like with a small notch at the top.
146→ * Width ≈ 85% of height — reads as a petal, not a leaf.
147→ *
148→ *        ╱ ‿ ╲        ← notch
149→ *      ╱       ╲
150→ *     (         )      ← round, fat body
151→ *      ╲       ╱
152→ *        ╲   ╱
153→ *          V           ← stem point
154→ */
155→function tracePetal(c: CanvasRenderingContext2D, s: number): void {
156→  // s = half-height; width is deliberately close to height
157→  const w = s * 0.85;
158→
159→  c.beginPath();
160→
161→  // Bottom stem point
162→  c.moveTo(0, s);
163→
164→  // Right side — sweeps up and out in a fat curve
165→  c.quadraticCurveTo(w * 1.1, s * 0.15, w * 0.2, -s * 0.85);
166→
167→  // Top-right → notch centre
168→  c.quadraticCurveTo(w * 0.05, -s * 0.55, 0, -s * 0.65);
169→
170→  // Notch centre → top-left
171→  c.quadraticCurveTo(-w * 0.05, -s * 0.55, -w * 0.2, -s * 0.85);
172→
173→  // Left side — mirror sweep back to stem
174→  c.quadraticCurveTo(-w * 1.1, s * 0.15, 0, s);
175→
176→  c.closePath();
177→}
178→
179→function updateAndDraw(time: number): void {
180→  if (!ctx || !canvas) return;
181→
182→  const { width, height } = canvas;
183→  ctx.clearRect(0, 0, width, height);
184→
185→  let currentFill = '';
186→  let visibleCount = 0;
187→
188→  for (const p of petals) {
189→    // Gentle fall + dual-frequency sway
190→    p.y += p.speedY;
191→    p.x +=
192→      Math.sin(p.phase + time * p.driftFreq) * p.drift +
193→      Math.sin(p.phase * 2.7 + time * p.flutterFreq) * p.flutter;
194→    p.rotation += p.rotationSpeed;
195→
196→    // Recycle off-screen (or skip during drain)
197→    if (p.y > height + p.size * 2) {
198→      if (state === 'draining') {
199→        continue;
200→      }
201→      p.y = -p.size * 2;
202→      p.x = Math.random() * width;
203→    }
204→
205→    visibleCount++;
206→
207→    if (p.x > width + p.size * 2) {
208→      p.x = -p.size * 2;
209→    } else if (p.x < -p.size * 2) {
210→      p.x = width + p.size * 2;
211→    }
212→
213→    // Fill batching
214→    const qOpacity = Math.round(p.opacity * 20) / 20;
215→    const nextFill = PALETTE[p.colorIdx] + qOpacity + ')';
216→    if (nextFill !== currentFill) {
217→      currentFill = nextFill;
218→      ctx.fillStyle = currentFill;
219→    }
220→
221→    // 3D wobble — gentle scaleX oscillation, always positive (no full flip)
222→    const wobble = p.wobbleBase + Math.sin(p.wobblePhase + time * p.wobbleSpeed) * p.wobbleAmp;
223→
224→    ctx.save();
225→    ctx.translate(p.x, p.y);
226→    ctx.rotate(p.rotation);
227→    ctx.scale(wobble, 1);
228→
229→    tracePetal(ctx, p.size);
230→    ctx.fill();
231→
232→    ctx.restore();
233→  }
234→
235→  // All petals have left the viewport — finish draining
236→  if (state === 'draining' && visibleCount === 0) {
237→    finalizeDrain();
238→    return;
239→  }
240→
241→  animationFrameId = requestAnimationFrame(updateAndDraw);
242→}
243→
244→function resizeCanvas(): void {
245→  if (!canvas) return;
246→  canvas.width = window.innerWidth;
247→  canvas.height = window.innerHeight;
248→}
249→
250→function startAnimation(): void {
251→  if (animationFrameId !== null) return;
252→  animationFrameId = requestAnimationFrame(updateAndDraw);
253→}
254→
255→function stopAnimation(): void {
256→  if (animationFrameId !== null) {
257→    cancelAnimationFrame(animationFrameId);
258→    animationFrameId = null;
259→  }
260→}
261→
262→function handleVisibilityChange(): void {
263→  if (document.visibilityState === 'visible') {
264→    startAnimation();
265→  } else {
266→    stopAnimation();
267→  }
268→}
269→
270→function enable(): void {
271→  if (state === 'active') return;
272→  if (state === 'draining') {
273→    // Cancel drain — resume normal particle recycling
274→    state = 'active';
275→    return;
276→  }
277→  state = 'active';
278→
279→  canvas = document.createElement('canvas');
280→  canvas.id = CANVAS_ID;
281→  canvas.style.cssText =
282→    'position:fixed;top:0;left:0;width:100%;height:100%;pointer-events:none;z-index:2147483647;';
283→  document.documentElement.appendChild(canvas);
284→
285→  ctx = canvas.getContext('2d');
286→  if (!ctx) {
287→    forceDisable();
288→    return;
289→  }
290→
291→  resizeCanvas();
292→  initPetals(canvas.width, canvas.height);
293→  startAnimation();
294→
295→  resizeHandler = resizeCanvas;
296→  window.addEventListener('resize', resizeHandler);
297→
298→  visibilityHandler = handleVisibilityChange;
